CREATE TABLE IF NOT EXISTS `Product` (`id` VARCHAR(191) NOT NULL,`code` VARCHAR(191) NOT NULL,`name` VARCHAR(191) NOT NULL,`category` VARCHAR(191) NOT NULL,`description` TEXT NULL,`listPrice` DECIMAL(15,2) NOT NULL,`active` TINYINT(1) NOT NULL DEFAULT 1,`createdAt` DATETIME NOT NULL,`updatedAt` DATETIME NOT NULL,PRIMARY KEY (`id`),UNIQUE KEY `Product_code_key` (`code`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `Quote` (`id` VARCHAR(191) NOT NULL,`quoteNo` VARCHAR(191) NOT NULL,`customerId` VARCHAR(191) NOT NULL,`opportunityId` VARCHAR(191) NULL,`status` ENUM('DRAFT','PENDING_APPROVAL','APPROVED','REJECTED','SENT','ACCEPTED','EXPIRED') NOT NULL DEFAULT 'DRAFT',`discountPct` INTEGER NOT NULL DEFAULT 0,`subtotal` DECIMAL(15,2) NOT NULL,`discountValue` DECIMAL(15,2) NOT NULL DEFAULT 0,`total` DECIMAL(15,2) NOT NULL,`validUntil` DATETIME NULL,`notes` TEXT NULL,`createdAt` DATETIME NOT NULL,`updatedAt` DATETIME NOT NULL,PRIMARY KEY (`id`),UNIQUE KEY `Quote_quoteNo_key` (`quoteNo`),CONSTRAINT `Quote_customerId_fkey` FOREIGN KEY (`customerId`) REFERENCES `Customer` (`id`),CONSTRAINT `Quote_opportunityId_fkey` FOREIGN KEY (`opportunityId`) REFERENCES `Opportunity` (`id`) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `QuoteItem` (`id` VARCHAR(191) NOT NULL,`quoteId` VARCHAR(191) NOT NULL,`productId` VARCHAR(191) NOT NULL,`quantity` INTEGER NOT NULL DEFAULT 1,`unitPrice` DECIMAL(15,2) NOT NULL,`createdAt` DATETIME NOT NULL,PRIMARY KEY (`id`),CONSTRAINT `QuoteItem_quoteId_fkey` FOREIGN KEY (`quoteId`) REFERENCES `Quote` (`id`) ON DELETE CASCADE,CONSTRAINT `QuoteItem_productId_fkey` FOREIGN KEY (`productId`) REFERENCES `Product` (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `Approval` (`id` VARCHAR(191) NOT NULL,`quoteId` VARCHAR(191) NOT NULL,`level` INTEGER NOT NULL,`status` VARCHAR(191) NOT NULL DEFAULT 'PENDING',`comment` TEXT NULL,`createdAt` DATETIME NOT NULL,`updatedAt` DATETIME NOT NULL,PRIMARY KEY (`id`),CONSTRAINT `Approval_quoteId_fkey` FOREIGN KEY (`quoteId`) REFERENCES `Quote` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
